const updateRoleOptimistic = `-- name: UpdateRoleOptimistic :one
UPDATE roles
SET name = $3,
    description = $4,
    version = version + 1,
    updated_at = $5
WHERE id = $1
  AND version = $2
  AND is_system = false
  AND archived_at IS NULL
RETURNING id, code, name, description, is_system, version, archived_at, created_at, updated_at
`

